descriptor.templateCss:
:host {
    height: 100%;
    width: 100%;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.ota-card {
    background: #ffffff;
    color: #1f2937;
    padding: 24px;
    border-radius: 20px;
    font-family: 'Inter', -apple-system, system-ui, sans-serif;
    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.08);

    /* This ensures it fills the height but respects padding */
    flex: 1;
    margin: 10px;
    min-height: 400px;  /* ADD THIS */
    overflow-y: auto;   /* ADD THIS */
    display: flex;
    flex-direction: column;
    min-width: 320px;
    /* Prevents the "tiny cube" look */
    border: 1px solid #f3f4f6;
}

.ota-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 24px;
    border-bottom: 2px solid #f3f4f6;
    padding-bottom: 16px;
}

.room-title {
    font-weight: 800;
    font-size: 1.3em;
    color: #2563eb;
    letter-spacing: -0.02em;
}

#status-tag {
    padding: 6px 12px;
    border-radius: 99px;
    font-size: 0.7em;
    font-weight: 800;
}

.status-pending {
    background: #fef3c7;
    color: #92400e;
}

.status-synced {
    background: #dcfce7;
    color: #166534;
}

.current-stats {
    display: flex;
    gap: 30px;
    margin-bottom: 24px;
    background: #f9fafb;
    padding: 18px;
    border-radius: 16px;
    border: 1px solid #f3f4f6;
}

.ota-inputs {
    display: grid;
    gap: 20px;
    margin-bottom: 24px;
}

.input-row input {
    width: 100%;
    box-sizing: border-box;
    /* Crucial for width: 100% */
    background: #fff;
    border: 2px solid #e5e7eb;
    padding: 12px;
    border-radius: 12px;
    font-weight: 500;
}

#updateBtn {
    margin-top: auto;
    /* Pushes button to bottom */
    width: 100%;
    background: linear-gradient(135deg, #3b82f6 0%, #8b5cf6 100%);
    color: #fff;
    border: none;
    padding: 16px;
    border-radius: 14px;
    font-weight: 700;
    cursor: pointer;
    transition: all 0.2s ease;
}

/* Animated pending badge */
.status-pending {
    background: #fff3cd;
    color: #856404;
    animation: pulse-pending 1.5s ease-in-out infinite;
}
.status-synced {
    background: #d1e7dd;
    color: #0a3622;
    animation: none;
}
.status-waiting {
    background: #cfe2ff;
    color: #084298;
    animation: pulse-pending 0.8s ease-in-out infinite;
}

@keyframes pulse-pending {
    0%, 100% { opacity: 1; transform: scale(1); }
    50%       { opacity: 0.6; transform: scale(1.05); }
}

/* Spinner for button loading state */
.spinner {
    display: inline-block;
    width: 14px;
    height: 14px;
    border: 2px solid rgba(255,255,255,0.4);
    border-top-color: white;
    border-radius: 50%;
    animation: spin 0.7s linear infinite;
    vertical-align: middle;
    margin-right: 6px;
}
@keyframes spin {
    to { transform: rotate(360deg); }
}

descriptor.controllerScript:
self.onInit = function() {
    const container = self.ctx.$container;
    const ctx = self.ctx;

    const ds = ctx.datasources && ctx.datasources[0];
    const entityName = ds ? (ds.entityName || "Unknown Room") : "Unknown Room";
    container.find('#targetId').text(entityName);

    let waitingForConfirmation = false;
    let pendingVersion = null;   // ← NEW: track locally instead of reading from TB

    function normalizeVersion(v) {
        if (v === undefined || v === null) return null;
        const n = parseFloat(v);
        return isNaN(n) ? String(v).trim() : String(n);
    }

    // ← CHANGED: no longer takes targetVer param — uses pendingVersion closure
    function updateStatus(currVer) {
        const statusTag = container.find('#status-tag');
        const nc = normalizeVersion(currVer);
        const np = normalizeVersion(pendingVersion);

        if (waitingForConfirmation && np && nc !== np) {
            statusTag.html('<span class="spinner"></span> AWAITING DEVICE')
                .removeClass('status-pending status-synced').addClass('status-waiting');
        } else if (!np || (nc && nc === np)) {
            waitingForConfirmation = false;
            pendingVersion = null;
            statusTag.text('UP TO DATE')
                .removeClass('status-pending status-waiting').addClass('status-synced');
        } else {
            statusTag.text('PENDING SYNC')
                .removeClass('status-synced status-waiting').addClass('status-pending');
        }
    }

    self.onDataUpdated = function() {
        const data = ctx.data;
        if (!data || !data.length) return;

        const currentDs = ctx.datasources && ctx.datasources[0];
        if (currentDs && currentDs.entityName) {
            container.find('#targetId').text(currentDs.entityName);
        }

        let currVersion = null;

        data.forEach(item => {
            const key = item.dataKey.name;
            // ← CHANGED: pick the data point with the highest timestamp (latest)
            if (!item.data || !item.data.length) return;
            const latest = item.data.reduce((best, d) => d[0] > best[0] ? d : best, item.data[0]);
            const val = latest[1];
            if (val === undefined || val === null) return;

            if (key === 'alpha')           container.find('#currAlpha').text(parseFloat(val).toFixed(3));
            if (key === 'beta')            container.find('#currBeta').text(parseFloat(val).toFixed(3));
            if (key === 'current_version') { currVersion = val; container.find('#currVersion').text(val); }
            // ← REMOVED: target_version no longer read from TB
        });

        updateStatus(currVersion);   // ← single arg now
    };

    container.find('#updateBtn').off('click').on('click', async function() {
        const currentDs = ctx.datasources && ctx.datasources[0];
        const ename = currentDs ? (currentDs.entityName || entityName) : entityName;

        if (!ename || ename === 'Unknown Room')
            return ctx.showErrorToast('No room selected');

        const nAlpha   = parseFloat(container.find('#newAlpha').val());
        const nBeta    = parseFloat(container.find('#newBeta').val());
        const nVersion = container.find('#newVersion').val().trim();

        if (isNaN(nAlpha) || isNaN(nBeta)) return ctx.showErrorToast('Enter valid numbers');
        if (!nVersion) return ctx.showErrorToast('Enter a target version');

        const btn = container.find('#updateBtn');
        btn.prop('disabled', true).html('<span class="spinner"></span>DEPLOYING...');

        const configStr = JSON.stringify({ alpha: nAlpha, beta: nBeta, version: nVersion });
        const buf = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(configStr));
        const sig = Array.from(new Uint8Array(buf)).map(b => b.toString(16).padStart(2,'0')).join('');

        const payload = JSON.stringify({
            config_data:    configStr,
            signature:      sig,
            target_version: nVersion,
            target:         ename
        });

        function doPublish() {
            const client = window.mqtt.connect(
                'ws://' + window.location.hostname + ':9001',
                { clientId: 'room_ota_' + Date.now().toString(36), clean: true, connectTimeout: 6000, reconnectPeriod: 0 }
            );

            client.on('connect', function() {
                client.publish('campus/b01/ota/config', payload, { qos: 1 }, function(err) {
                    client.end(true);
                    if (err) {
                        ctx.showErrorToast('Publish failed: ' + err.message);
                    } else {
                        ctx.showSuccessToast('Deployed to ' + ename);
                        // ← CHANGED: set pendingVersion locally, no TB read needed
                        pendingVersion = nVersion;
                        waitingForConfirmation = true;
                        updateStatus(container.find('#currVersion').text());
                    }
                    btn.prop('disabled', false).text('DEPLOY EVOLUTION');
                });
            });

            client.on('error', function(err) {
                client.end(true);
                ctx.showErrorToast('MQTT error: ' + err.message);
                btn.prop('disabled', false).text('DEPLOY EVOLUTION');
            });
        }

        if (window.mqtt) {
            doPublish();
        } else {
            var s = document.createElement('script');
            s.src = 'https://unpkg.com/mqtt@5/dist/mqtt.min.js';
            s.onload  = doPublish;
            s.onerror = function() {
                ctx.showErrorToast('Failed to load MQTT.js');
                btn.prop('disabled', false).text('DEPLOY EVOLUTION');
            };
            document.head.appendChild(s);
        }
    });
};

self.typeParameters = function() {
    return { maxDatasources: 1, maxDataKeys: 10, singleEntity: true, useDatasource: true };
};

